{
  "lean_declaration": "theorem binom_rec {R : Type*} [CommRing R] [BinomialRing R] [NatPowAssoc R] (r : R) (k : ℕ) :\n    Ring.choose (r + 1) (k + 1) = Ring.choose r k + Ring.choose r (k + 1) := by\n  have hk : 0 < k + 1 := Nat.succ_pos k\n  have h := pascal_identity_ring (r + 1) (k + 1) hk\n  have hsub1 : (r + 1) - 1 = r := by ring\n  have hsub2 : ((k + 1 : ℕ) - 1) = k := by simp\n  simpa [hsub1, hsub2] using h",
  "declaration_name": "binom_rec",
  "used_context": [
    "pascal_identity_ring",
    "Nat.succ_pos",
    "ring",
    "simp"
  ],
  "notes": [
    "Formalizes the successor-form Pascal identity (Ring.choose_succ_succ) using the locally available pascal_identity_ring lemma, which already encodes the recurrence for positive lower indices."
  ]
}
